1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Result = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	const COMPONENT_UNIT_PRICE = 25;
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const roundPremium = (amount: number): number => Math.ceil(amount);
27	
28	const priceForComponentCount = (count: number): number =>
29	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
30	
31	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
32	  let total = 0;
33	  for (const count of componentCountsByType.values()) {
34	    total += priceForComponentCount(count);
35	  }
36	  return total;
37	};
38	
39	const baseForItems = (items: Item[]): number => {
40	  const componentCountsByType = new Map<string, number>();
41	  let nonComponentBase = 0;
42	  for (const item of items) {
43	    if (isComponent(item)) {
44	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
45	    } else {
46	      nonComponentBase += basePremiumFor(item);
47	    }
48	  }
49	  return nonComponentBase + sumComponentBase(componentCountsByType);
50	};
51	
52	const quotePremium = (items: Item[]): number => {
53	  const base = baseForItems(items);
54	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
55	  return roundPremium(base + firstInsuranceSurcharge + PROCESSING_FEE);
56	};
57	
58	export const runScenario = (input: {
59	  customer: { yearsWithMHPCO: number };
60	  steps: Step[];
61	}): { results: Result[] } => {
62	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
63	  return { results };
64	};
